mapper.select:
SELECT id, title, content, biz_type, priority, is_read, resource_biz_type, resource_id, is_deleted, sender_id, target_id, create_time, read_time, expire_time, extra_info FROM byai_notification
is_deleted = '0'
AND target_id = #{query.targetId}
AND title LIKE CONCAT('%', #{query.title}, '%')
AND content LIKE CONCAT('%', #{query.content}, '%')
AND biz_type = #{query.bizType}
AND priority = #{query.priority}
AND is_read = #{query.isRead}
AND resource_biz_type = #{query.resourceBizType}
AND resource_id IN
#{resourceId}
AND create_time >= CAST(#{query.createStartTime} AS DATE)
AND create_time < CAST(#{query.createEndTime} AS DATE) + INTERVAL '1 day'
AND read_time >= CAST(#{query.readStartTime} AS DATE)
AND read_time < CAST(#{query.readEndTime} AS DATE) + INTERVAL '1 day'
ORDER BY is_read ASC, CASE WHEN is_read = '0' THEN create_time ELSE read_time END DESC

mapper.update:
update byai_notification set is_read = '1', read_time = CURRENT_TIMESTAMP where id in
#{id}
and target_id = #{targetId} and is_deleted = '0'
